// MARK: - Local Network Address Validator

struct LocalNetworkValidator {
    
    /// Validates that a host string is a private/local network IP address.
    /// Allowed ranges: 10.x.x.x, 172.16-31.x.x, 192.168.x.x, 169.254.x.x, 127.x.x.x
    static func isLocalAddress(_ host: String) -> Bool {
        // Strip port if present
        let hostOnly = host.components(separatedBy: ":").first ?? host
        
        let components = hostOnly.components(separatedBy: ".")
        guard components.count == 4,
              let first = Int(components[0]),
              let second = Int(components[1]),
              components.allSatisfy({ Int($0) != nil && Int($0)! >= 0 && Int($0)! <= 255 }) else {
            // Also allow .local mDNS names
            return hostOnly.hasSuffix(".local")
        }
        
        switch first {
        case 10:
            return true // 10.0.0.0/8
        case 172:
            return (16...31).contains(second) // 172.16.0.0/12
        case 192:
            return second == 168 // 192.168.0.0/16
        case 169:
            return second == 254 // 169.254.0.0/16 (link-local)
        case 127:
            return true // 127.0.0.0/8 (loopback)
        default:
            return false
        }
    }
}

