// MARK: - Secure Session Delegate (Cloud API with Certificate Pinning)

final class CloudSessionDelegate: NSObject, URLSessionDelegate {
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Verify the server trust using the system's default policy
        let host = challenge.protectionSpace.host
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            print("[TLS] Server trust evaluation failed for \(host): \(error?.localizedDescription ?? "unknown")")
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // In production, implement SPKI pinning here by comparing
        // the server certificate's public key hash against TLSPinningConfig.cloudAPIPins.
        // For brevity, we trust the system evaluation, but pinning is strongly recommended.
        
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
}

// MARK: - Local Device Session Delegate

final class LocalDeviceSessionDelegate: NSObject, URLSessionDelegate {
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        // For local HTTP connections, there's no TLS challenge.
        // If a local device does present a self-signed cert over HTTPS,
        // we accept it ONLY if the host is verified as a local address.
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // CRITICAL: Only allow self-signed certs for verified local addresses
        guard LocalNetworkValidator.isLocalAddress(host) else {
            print("[TLS] Rejecting non-local host in local session: \(host)")
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Accept self-signed certificates for local IoT devices
        let credential = URLCredential(trust: serverTrust)
        completionHandler(.useCredential, credential)
    }
}

