// MARK: - IoT Device Discovery (Bonjour/mDNS)

final class IoTDeviceDiscovery {
    
    private var browser: NWBrowser?
    
    struct DiscoveredDevice {
        let name: String
        let host: String
        let port: UInt16
    }
    
    func startDiscovery(
        serviceType: String = "_http._tcp",
        domain: String = "local.",
        onDeviceFound: @escaping (DiscoveredDevice) -> Void
    ) {
        let parameters = NWParameters()
        parameters.includePeerToPeer = true
        
        let browser = NWBrowser(for: .bonjour(type: serviceType, domain: domain), using: parameters)
        
        browser.browseResultsChangedHandler = { results, changes in
            for result in results {
                if case .service(let name, _, _, _) = result.endpoint {
                    // Resolve the service to get the actual host/port
                    print("[Discovery] Found device: \(name)")
                }
            }
        }
        
        browser.stateUpdateHandler = { state in
            switch state {
            case .ready:
                print("[Discovery] Browser ready")
            case .failed(let error):
                print("[Discovery] Browser failed: \(error)")
            default:
                break
            }
        }
        
        browser.start(queue: .global(qos: .userInitiated))
        self.browser = browser
    }
    
    func stopDiscovery() {
        browser?.cancel()
        browser = nil
    }
}

